78	  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
79	  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");
80	
81	  // Rounding up in MHPCO's favor
82	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
