1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const BLOCK_SIZE = 3;
17	const RUNE_BLOCK_PRICE = 60;
18	
19	const isRune = (item: { type: string }): boolean => item.type === "rune";
20	
21	export function quote(items: { type: string }[], context: QuoteContext): number {
22	  const runeCount = items.filter(isRune).length;
23	
24	  const runeBasePremium =
25	    runeCount === BLOCK_SIZE ? RUNE_BLOCK_PRICE : runeCount * BASE_PREMIUM.rune;
26	
27	  const nonRuneBasePremium = items
28	    .filter((item) => !isRune(item))
29	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
30	
31	  return nonRuneBasePremium + runeBasePremium + POLICY_FEE;
32	}
33	
34	export function claim(): unknown {
35	  return undefined;
36	}
